import { CategoryLayout } from '@/layouts/CategoryLayout';
import { GameGrid } from '@/components/GameGrid';
import { HeroBanner } from '@/components/HeroBanner';
import { FeaturedGames } from '@/components/FeaturedGames';
import type { GetStaticProps } from 'next';

interface Props { initialGames: Game[]; totalCount: number; }

export default function NewCategory({ initialGames, totalCount }: Props) {
  return (
    <CategoryLayout
      title="New Games — Free Online | YallaPlays"
      description="Fresh games added to YallaPlays this week. Play free — no download, no registration."
      category="new"
    >
      <HeroBanner
        title="✨ New Games"
        subtitle="Fresh games added to YallaPlays this week"
        totalCount={totalCount}
      />
      <FeaturedGames category="new" limit={3} />
      <GameGrid
        category="new"
        sortField="created_at"
        pageSize={24}
        initialData={initialGames}
        filters={['Action', 'Sports', 'Puzzle', 'Racing', 'Strategy']}
      />
    </CategoryLayout>
  );
}

export const getStaticProps: GetStaticProps = async () => {
  return { props: { initialGames: [], totalCount: 0 }, revalidate: 300 };
};
